class Solution:
    def uniqueLetterString(self, s):
        n = len(s)
        total = 0
        for i in range(n):
            seen = {}
            for j in range(i, n):
                seen[s[j]] = seen.get(s[j], 0) + 1
                unique = sum(1 for v in seen.values() if v == 1)
                total += unique
        return total

