class Solution:
    def uniqueLetterString(self, s):
        last = {}
        prev = {}
        total = 0
        n = len(s)
        index = {}
        positions = {}
        for i, ch in enumerate(s):
            positions.setdefault(ch, []).append(i)
        for ch, idxs in positions.items():
            m = len(idxs)
            for k in range(m):
                cur = idxs[k]
                left = idxs[k - 1] if k > 0 else -1
                right = idxs[k + 1] if k + 1 < m else n
                total += (cur - left) * (right - cur)
        return total

