var uniqueLetterString = function(s) {
    const n = s.length;
    const positions = new Map();
    for (let i = 0; i < n; i++) {
        const ch = s[i];
        if (!positions.has(ch)) positions.set(ch, []);
        positions.get(ch).push(i);
    }
    let total = 0;
    for (const idxs of positions.values()) {
        const m = idxs.length;
        for (let k = 0; k < m; k++) {
            const cur = idxs[k];
            const left = k > 0 ? idxs[k - 1] : -1;
            const right = k + 1 < m ? idxs[k + 1] : n;
            total += (cur - left) * (right - cur);
        }
    }
    return total;
};
